// client/components/format.js
function formatWatchTime(value2) {
  if (!Number.isFinite(value2)) return "00:00";
  const total = Math.max(0, Math.floor(value2));
  const minutes = Math.floor(total / 60);
  const seconds = total % 60;
  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
}
function userWatchText(user, isLive = false) {
  const watch3 = user.watchState;
  const fresh = watch3 && Date.now() - watch3.updatedAt < 8e3;
  if (!fresh) return user.speaking ? "说话中" : "在线";
  const stateText = watch3.paused ? "暂停" : watch3.waiting ? "缓冲" : "播放";
  const timeText = isLive ? "" : ` ${formatWatchTime(watch3.currentTime)}`;
  return `${stateText}${timeText} · 缓冲${Math.floor(watch3.bufferedAhead || 0)}s`;
}

